mapper.select:
/* peak 조회 */
select
site_id, std_timestamp, sum(peak_val) as peak_val
from (
select
peak_idx, site_id, std_timestamp, std_date, peak_val, peak_timestamp, peak_date, reg_date, mod_date
from tb_peak
where site_id = #{siteId }

    and std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and
    str_to_date(#{selTermTo },'%Y%m%d%H%i%s')

) a
group by site_id, std_timestamp
order by std_timestamp
